import{_ as t,o as a,c as r,a2 as i}from"./chunks/framework.B72_uj9U.js";const m=JSON.parse('{"title":"DINOForge - Product Requirements Document","description":"","frontmatter":{},"headers":[],"relativePath":"PRD.md","filePath":"PRD.md","lastUpdated":1773130681000}'),o={name:"PRD.md"};function s(n,e,d,l,c,h){return a(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="dinoforge-product-requirements-document" tabindex="-1">DINOForge - Product Requirements Document <a class="header-anchor" href="#dinoforge-product-requirements-document" aria-label="Permalink to &quot;DINOForge - Product Requirements Document&quot;">​</a></h1><p><strong>Version</strong>: 0.1.0 <strong>Status</strong>: Draft <strong>Created</strong>: 2026-03-09 <strong>Author</strong>: kooshapari + Agent Org</p><hr><h2 id="_0-document-purpose" tabindex="-1">0. Document Purpose <a class="header-anchor" href="#_0-document-purpose" aria-label="Permalink to &quot;0. Document Purpose&quot;">​</a></h2><p>This document defines the product and architecture foundation for <strong>DINOForge</strong>, a general-purpose mod platform and agent-oriented development scaffold for <strong>Diplomacy is Not an Option (DINO)</strong>.</p><p>It is intentionally broader than a single warfare mod. The goal is to create a reusable framework that can support:</p><ul><li>Warfare total conversions (Star Wars, Modern, Futuristic)</li><li>Balance mods</li><li>Content packs</li><li>Wave/AI mods</li><li>Scenario mods</li><li>UI/QoL mods</li><li>Debugging and introspection tools</li><li>Future domain-specific mod extensions</li></ul><hr><h2 id="_1-executive-summary" tabindex="-1">1. Executive Summary <a class="header-anchor" href="#_1-executive-summary" aria-label="Permalink to &quot;1. Executive Summary&quot;">​</a></h2><h3 id="_1-1-product-name" tabindex="-1">1.1 Product Name <a class="header-anchor" href="#_1-1-product-name" aria-label="Permalink to &quot;1.1 Product Name&quot;">​</a></h3><p><strong>DINOForge</strong></p><h3 id="_1-2-product-definition" tabindex="-1">1.2 Product Definition <a class="header-anchor" href="#_1-2-product-definition" aria-label="Permalink to &quot;1.2 Product Definition&quot;">​</a></h3><p>DINOForge is a <strong>general mod runtime, SDK, pack system, and tooling platform</strong> for DINO, built for <strong>agent-driven development</strong> first.</p><p>It is not just a mod. It is a <strong>mod operating system</strong> for this game.</p><h3 id="_1-3-why-this-exists" tabindex="-1">1.3 Why This Exists <a class="header-anchor" href="#_1-3-why-this-exists" aria-label="Permalink to &quot;1.3 Why This Exists&quot;">​</a></h3><p>DINO modding requires nontrivial reverse engineering and ECS-aware patching. There is no polished official mod SDK. Ad hoc mod development is brittle, repetitive, and poor for long-term iteration.</p><p>The intended development model is <strong>agent-driven</strong>: the human acts as product owner, tester, design director, and failure reporter. Agents handle all coding.</p><p>This means the system must be designed for:</p><ul><li>Rigid abstractions</li><li>Declarative schemas</li><li>Machine-checkable contracts</li><li>Validation pipelines</li><li>Debug surfaces</li><li>Deterministic extension points</li></ul><h3 id="_1-4-strategic-outcome" tabindex="-1">1.4 Strategic Outcome <a class="header-anchor" href="#_1-4-strategic-outcome" aria-label="Permalink to &quot;1.4 Strategic Outcome&quot;">​</a></h3><p>The first major use case is a <strong>warfare domain plugin</strong> supporting modern and Star Wars themed conversions. The platform itself supports broader mod classes.</p><p><strong>Target end state:</strong></p><blockquote><p>New DINO mods can be created primarily by defining validated pack manifests, schemas, mappings, and assets through the DINOForge SDK and toolchain, with minimal or no fresh reverse engineering.</p></blockquote><hr><h2 id="_2-vision" tabindex="-1">2. Vision <a class="header-anchor" href="#_2-vision" aria-label="Permalink to &quot;2. Vision&quot;">​</a></h2><h3 id="_2-1-vision-statement" tabindex="-1">2.1 Vision Statement <a class="header-anchor" href="#_2-1-vision-statement" aria-label="Permalink to &quot;2.1 Vision Statement&quot;">​</a></h3><p>Create the canonical mod platform for DINO that transforms brittle one-off reverse-engineered hacks into a structured, extensible, testable, agent-operable ecosystem.</p><h3 id="_2-2-product-principles" tabindex="-1">2.2 Product Principles <a class="header-anchor" href="#_2-2-product-principles" aria-label="Permalink to &quot;2.2 Product Principles&quot;">​</a></h3><ol><li><strong>Wrap, don&#39;t handroll</strong> - Use established libraries/tools and wrap them. Never build from scratch what a proven package already solves. This is a vibecoding-only environment: agents produce more reliable output integrating proven code than generating novel implementations. Every handrolled component is a liability; every wrapped dependency is borrowed reliability.</li><li><strong>Framework before content</strong> - The first product is the platform, not the themed mod.</li><li><strong>Declarative before imperative</strong> - Prefer pack manifests, schemas, mappings, and registries over custom patch code.</li><li><strong>Stable abstraction over unstable internals</strong> - Low-level engine glue must be isolated from mod authoring surfaces.</li><li><strong>Agent-first repository design</strong> - The codebase and docs must optimize for autonomous agent development.</li><li><strong>Observability is a first-class feature</strong> - Runtime must explain itself through logs, overlays, reports, validators.</li><li><strong>Domain extensibility</strong> - Warfare is the first domain plugin, not the only one.</li><li><strong>Compatibility-aware packaging</strong> - Mods must be packs with explicit dependencies, conflicts, versions.</li><li><strong>Graceful degradation</strong> - Missing assets/broken mappings fail loudly with fallbacks where safe.</li></ol><hr><h2 id="_3-users" tabindex="-1">3. Users <a class="header-anchor" href="#_3-users" aria-label="Permalink to &quot;3. Users&quot;">​</a></h2><h3 id="primary-user" tabindex="-1">Primary User <a class="header-anchor" href="#primary-user" aria-label="Permalink to &quot;Primary User&quot;">​</a></h3><ul><li>The mod platform owner / product director using agent-driven development</li></ul><h3 id="secondary-users" tabindex="-1">Secondary Users <a class="header-anchor" href="#secondary-users" aria-label="Permalink to &quot;Secondary Users&quot;">​</a></h3><ul><li>Autonomous coding agents</li><li>Validation/diagnosis agents</li><li>Content-authoring agents</li><li>Future technical contributors</li></ul><h3 id="tertiary-users" tabindex="-1">Tertiary Users <a class="header-anchor" href="#tertiary-users" aria-label="Permalink to &quot;Tertiary Users&quot;">​</a></h3><ul><li>End-users who install packs or total conversions built on DINOForge</li></ul><hr><h2 id="_4-user-needs" tabindex="-1">4. User Needs <a class="header-anchor" href="#_4-user-needs" aria-label="Permalink to &quot;4. User Needs&quot;">​</a></h2><h3 id="product-owner-needs" tabindex="-1">Product Owner Needs <a class="header-anchor" href="#product-owner-needs" aria-label="Permalink to &quot;Product Owner Needs&quot;">​</a></h3><ul><li>Request features in natural language</li><li>Avoid reading source code</li><li>Receive clear diagnostics when things fail</li><li>Iterate on gameplay, balance, and theming quickly</li><li>Add new mod concepts without fresh reverse engineering each time</li></ul><h3 id="agent-needs" tabindex="-1">Agent Needs <a class="header-anchor" href="#agent-needs" aria-label="Permalink to &quot;Agent Needs&quot;">​</a></h3><ul><li>Clear public APIs</li><li>Typed schemas</li><li>Examples and templates</li><li>Deterministic build/test flows</li><li>Bounded ownership areas</li><li>Machine-readable contracts</li><li>Debugging tools and reports</li></ul><h3 id="end-user-needs" tabindex="-1">End-User Needs <a class="header-anchor" href="#end-user-needs" aria-label="Permalink to &quot;End-User Needs&quot;">​</a></h3><ul><li>Install packs safely</li><li>Understand compatibility and conflicts</li><li>Get stable gameplay behavior</li><li>Receive understandable errors when packs fail</li></ul><hr><h2 id="_5-goals" tabindex="-1">5. Goals <a class="header-anchor" href="#_5-goals" aria-label="Permalink to &quot;5. Goals&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Goal</th></tr></thead><tbody><tr><td>G1</td><td>General mod framework - reusable runtime + SDK + pack system</td></tr><tr><td>G2</td><td>Agent-safe development surface - declarative definitions + stable SDK</td></tr><tr><td>G3</td><td>Runtime observability - logs, overlays, inspectors, validation reports</td></tr><tr><td>G4</td><td>Domain plugins - modular extensions (warfare, economy, UI, scenarios)</td></tr><tr><td>G5</td><td>Pack-based delivery - installable, composable packs with metadata</td></tr><tr><td>G6</td><td>Low-level change isolation - engine/ECS breakage confined to runtime layer</td></tr></tbody></table><hr><h2 id="_6-non-goals" tabindex="-1">6. Non-Goals <a class="header-anchor" href="#_6-non-goals" aria-label="Permalink to &quot;6. Non-Goals&quot;">​</a></h2><table tabindex="0"><thead><tr><th>ID</th><th>Non-Goal</th></tr></thead><tbody><tr><td>NG1</td><td>Perfect official-grade SDK parity</td></tr><tr><td>NG2</td><td>Full automation of every conceivable mod on day one</td></tr><tr><td>NG3</td><td>Full custom asset pipeline at v1</td></tr><tr><td>NG4</td><td>Human-code-review-first workflows</td></tr></tbody></table><hr><h2 id="_7-core-functional-requirements" tabindex="-1">7. Core Functional Requirements <a class="header-anchor" href="#_7-core-functional-requirements" aria-label="Permalink to &quot;7. Core Functional Requirements&quot;">​</a></h2><h3 id="fr1-runtime-bootstrap" tabindex="-1">FR1. Runtime Bootstrap <a class="header-anchor" href="#fr1-runtime-bootstrap" aria-label="Permalink to &quot;FR1. Runtime Bootstrap&quot;">​</a></h3><p>Initialize inside DINO and establish version-aware runtime integration via BepInEx + <code>ecs_plugins</code> loader.</p><h3 id="fr2-runtime-introspection" tabindex="-1">FR2. Runtime Introspection <a class="header-anchor" href="#fr2-runtime-introspection" aria-label="Permalink to &quot;FR2. Runtime Introspection&quot;">​</a></h3><p>Provide access to discovered systems, entities, components, resources, or equivalent game structures.</p><h3 id="fr3-stable-sdk-layer" tabindex="-1">FR3. Stable SDK Layer <a class="header-anchor" href="#fr3-stable-sdk-layer" aria-label="Permalink to &quot;FR3. Stable SDK Layer&quot;">​</a></h3><p>Expose high-level extension interfaces for defining mods without requiring direct low-level runtime patching for common cases.</p><h3 id="fr4-registry-system" tabindex="-1">FR4. Registry System <a class="header-anchor" href="#fr4-registry-system" aria-label="Permalink to &quot;FR4. Registry System&quot;">​</a></h3><p>Support registries for core extensible domains:</p><ul><li>Units, Buildings, Weapons, Projectiles, Effects</li><li>Audio Packs, UI Skins, Doctrines, Factions</li><li>Wave Templates, Behaviors, Scenario Scripts</li><li>Tech Nodes, Localization Bundles</li></ul><h3 id="fr5-pack-manifest-system" tabindex="-1">FR5. Pack Manifest System <a class="header-anchor" href="#fr5-pack-manifest-system" aria-label="Permalink to &quot;FR5. Pack Manifest System&quot;">​</a></h3><p>Support installable pack manifests with:</p><ul><li>id, version, dependencies, conflicts</li><li>framework_version compatibility range</li><li>load order hints</li><li>content declarations</li></ul><h3 id="fr6-schema-validation" tabindex="-1">FR6. Schema Validation <a class="header-anchor" href="#fr6-schema-validation" aria-label="Permalink to &quot;FR6. Schema Validation&quot;">​</a></h3><p>Validate pack schemas, dependency graphs, asset references, and ECS registration conflicts before game boot.</p><h3 id="fr7-pack-compiler" tabindex="-1">FR7. Pack Compiler <a class="header-anchor" href="#fr7-pack-compiler" aria-label="Permalink to &quot;FR7. Pack Compiler&quot;">​</a></h3><p>Build tool that validates schema, resolves references, checks missing assets, checks circular deps, builds pack artifacts, emits compatibility metadata.</p><h3 id="fr8-domain-plugin-architecture" tabindex="-1">FR8. Domain Plugin Architecture <a class="header-anchor" href="#fr8-domain-plugin-architecture" aria-label="Permalink to &quot;FR8. Domain Plugin Architecture&quot;">​</a></h3><p>Support modular domain extensions that add domain-specific registries, schemas, and behaviors without modifying core.</p><h3 id="fr9-debug-and-diagnostics" tabindex="-1">FR9. Debug and Diagnostics <a class="header-anchor" href="#fr9-debug-and-diagnostics" aria-label="Permalink to &quot;FR9. Debug and Diagnostics&quot;">​</a></h3><p>Provide runtime logs, in-game debug overlay, entity dump tools, and validation reports.</p><h3 id="fr10-content-override-model" tabindex="-1">FR10. Content Override Model <a class="header-anchor" href="#fr10-content-override-model" aria-label="Permalink to &quot;FR10. Content Override Model&quot;">​</a></h3><p>Support layered content overrides: base game -&gt; framework defaults -&gt; domain plugin -&gt; pack overrides.</p><hr><h2 id="_8-supported-mod-classes" tabindex="-1">8. Supported Mod Classes <a class="header-anchor" href="#_8-supported-mod-classes" aria-label="Permalink to &quot;8. Supported Mod Classes&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Category</th><th>Description</th></tr></thead><tbody><tr><td>Content</td><td>Units, buildings, projectiles, effects, icons, names, localization, audio, tech tree</td></tr><tr><td>Balance</td><td>Stats, costs, spawn sizes, upgrade tuning, HP/armor/accuracy/fire rate, economy rates</td></tr><tr><td>Ruleset</td><td>Research requirements, build prereqs, wave timings, victory/loss, population, factions</td></tr><tr><td>AI/Wave</td><td>Enemy composition, attack priorities, target selection, escalation logic, event scripting</td></tr><tr><td>UI/UX</td><td>HUD elements, tooltips, overlays, debug inspectors, minimap, faction themes</td></tr><tr><td>Scenario</td><td>Mission scripting, map conditions, scripted events, starting states, faction matchups</td></tr><tr><td>Utility</td><td>Profiler, entity inspector, hot reload, content diff, compatibility checker, save analyzer</td></tr></tbody></table><hr><h2 id="_9-three-product-architecture" tabindex="-1">9. Three-Product Architecture <a class="header-anchor" href="#_9-three-product-architecture" aria-label="Permalink to &quot;9. Three-Product Architecture&quot;">​</a></h2><h3 id="product-a-runtime-hook-layer" tabindex="-1">Product A - Runtime / Hook Layer <a class="header-anchor" href="#product-a-runtime-hook-layer" aria-label="Permalink to &quot;Product A - Runtime / Hook Layer&quot;">​</a></h3><p>Low-level engine glue. Most brittle, fewest agents should touch.</p><ul><li>Boot into DINO</li><li>Locate systems/entities/components/assets</li><li>Expose safe patch points</li><li>Handle version checks and rollback/fallback</li><li>Expose debug and diagnostics</li></ul><h3 id="product-b-mod-api-domain-sdk" tabindex="-1">Product B - Mod API / Domain SDK <a class="header-anchor" href="#product-b-mod-api-domain-sdk" aria-label="Permalink to &quot;Product B - Mod API / Domain SDK&quot;">​</a></h3><p>The real scaffold. Where trivial modding becomes possible.</p><ul><li>High-level mod definition interfaces</li><li>Hide engine internals</li><li>Provide schemas, registries, validators, pack loaders</li><li>Support multiple mod classes</li></ul><h3 id="product-c-mod-packs-content-packs" tabindex="-1">Product C - Mod Packs / Content Packs <a class="header-anchor" href="#product-c-mod-packs-content-packs" aria-label="Permalink to &quot;Product C - Mod Packs / Content Packs&quot;">​</a></h3><p>Where actual mods live. Mostly declarative and content-driven.</p><ul><li>Warfare modern pack, warfare Star Wars pack</li><li>Balance packs, economy packs</li><li>QoL/UI packs, debug packs</li></ul><hr><h2 id="_10-first-use-case-warfare-domain" tabindex="-1">10. First-Use-Case: Warfare Domain <a class="header-anchor" href="#_10-first-use-case-warfare-domain" aria-label="Permalink to &quot;10. First-Use-Case: Warfare Domain&quot;">​</a></h2><h3 id="faction-archetypes-3-mechanical-families" tabindex="-1">Faction Archetypes (3 mechanical families) <a class="header-anchor" href="#faction-archetypes-3-mechanical-families" aria-label="Permalink to &quot;Faction Archetypes (3 mechanical families)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Archetype</th><th>Traits</th><th>Used By</th></tr></thead><tbody><tr><td>Order</td><td>Strong line infantry, reliable DPS, better defenses, higher unit cost</td><td>Republic, West</td></tr><tr><td>Industrial Swarm</td><td>Larger numbers, cheaper core, expendable, strong siege</td><td>CIS, Classic West Enemy</td></tr><tr><td>Asymmetric</td><td>Light units, mobility, ambush, raid pressure, structure harassment</td><td>Guerrilla West Enemy</td></tr></tbody></table><h3 id="theme-packs" tabindex="-1">Theme Packs <a class="header-anchor" href="#theme-packs" aria-label="Permalink to &quot;Theme Packs&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Pack</th><th>Factions</th><th>Theme</th></tr></thead><tbody><tr><td>Republic vs CIS</td><td>Galactic Republic, CIS</td><td>Star Wars Clone Wars</td></tr><tr><td>West vs Enemies</td><td>West, Classic West Enemy, Guerrilla West Enemy</td><td>Modern Warfare</td></tr></tbody></table><h3 id="implementation-order" tabindex="-1">Implementation Order <a class="header-anchor" href="#implementation-order" aria-label="Permalink to &quot;Implementation Order&quot;">​</a></h3><ol><li>West vs Classic West Enemy (easiest, proves framework)</li><li>Republic vs CIS (harder art/audio, proves theme-skin abstraction)</li><li>West vs Guerrilla Enemy (asymmetry, hardest balance)</li></ol><hr><h2 id="_11-milestone-roadmap" tabindex="-1">11. Milestone Roadmap <a class="header-anchor" href="#_11-milestone-roadmap" aria-label="Permalink to &quot;11. Milestone Roadmap&quot;">​</a></h2><table tabindex="0"><thead><tr><th>#</th><th>Milestone</th><th>Description</th><th>Status</th></tr></thead><tbody><tr><td>M0</td><td>Reverse-Engineering Harness</td><td>Install BepInEx, confirm plugin loading, test plugin, dump entities</td><td>Done</td></tr><tr><td>M1</td><td>Runtime Scaffold</td><td>Bootstrap plugin, version detection, logging, ECS introspection, debug overlay</td><td>Done</td></tr><tr><td>M2</td><td>Generic Mod SDK</td><td>Pack manifest format, registry system, schema validation, override model, dependency resolver</td><td>In Progress</td></tr><tr><td>M3</td><td>Dev Tooling</td><td>Pack compiler CLI, validator CLI, test harness, diff tools, diagnostics</td><td>In Progress</td></tr><tr><td>M3.5</td><td>QA Harness</td><td>BepInEx QA plugin with IPC (named pipe/WebSocket), external test driver, ECS state assertions, CI-runnable integration tests</td><td>Planned</td></tr><tr><td>M4</td><td>Warfare Domain Plugin</td><td>Factions, doctrines, unit classes, weapons, waves, defenses</td><td>Planned</td></tr><tr><td>M5</td><td>First Example Packs</td><td>West vs Classic Enemy, then Republic vs CIS, then Guerrilla</td><td>Planned</td></tr><tr><td>M6</td><td>Content Polish</td><td>Signature structures, better models, faction audio, campaign wrappers</td><td>Planned</td></tr></tbody></table><hr><h2 id="_12-technical-risks" tabindex="-1">12. Technical Risks <a class="header-anchor" href="#_12-technical-risks" aria-label="Permalink to &quot;12. Technical Risks&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Risk</th><th>Impact</th><th>Mitigation</th></tr></thead><tbody><tr><td>ECS patch fragility</td><td>Game updates break hooks</td><td>Isolate hook points, version gate, component dumps</td></tr><tr><td>Performance collapse</td><td>Harmony path costs perf</td><td>ECS-native modding, batch stat application, cache queries</td></tr><tr><td>Asset pipeline pain</td><td>Model import blocked</td><td>Treat models as optional, build around text/icons/VFX/stats first</td></tr><tr><td>Asymmetry imbalance</td><td>Guerrilla faction broken</td><td>Build peer warfare first, add insurgent after baseline balance</td></tr><tr><td>No official API docs</td><td>Discovery is manual</td><td>Build own introspection tools, maintain component dumps</td></tr></tbody></table><hr><h2 id="_13-success-criteria" tabindex="-1">13. Success Criteria <a class="header-anchor" href="#_13-success-criteria" aria-label="Permalink to &quot;13. Success Criteria&quot;">​</a></h2><blockquote><p>A new mod can be created mostly by editing validated pack files and running the toolchain, without new reverse engineering.</p></blockquote><p>If every mod still needs runtime surgery, the framework failed.</p><hr><h2 id="_14-reference-models" tabindex="-1">14. Reference Models <a class="header-anchor" href="#_14-reference-models" aria-label="Permalink to &quot;14. Reference Models&quot;">​</a></h2><p>Best modding DX/UX to emulate:</p><table tabindex="0"><thead><tr><th>System</th><th>What to Copy</th></tr></thead><tbody><tr><td>Factorio</td><td>API shape, manifests, dependency/version handling, distribution</td></tr><tr><td>RimWorld</td><td>Split between declarative content and imperative code patches</td></tr><tr><td>Satisfactory/BepInEx</td><td>Mod loaders, plugin bootstrap, community tooling</td></tr><tr><td>Minecraft Bedrock</td><td>Pack schemas, folder conventions, generation/validation</td></tr><tr><td>UEFN/Roblox</td><td>End-to-end creation pipeline concept</td></tr></tbody></table><p><strong>What NOT to copy:</strong></p><ul><li>Raw BepInEx &quot;drop DLL in plugins and pray&quot;</li><li>Undocumented patch soup</li><li>Hidden load order rules</li><li>Discord-as-documentation</li></ul>',113)])])}const p=t(o,[["render",s]]);export{m as __pageData,p as default};
